SELECT * FROM standard_documents

    AND (title LIKE CONCAT('%',#{keyword},'%') OR summary LIKE CONCAT('%',#{keyword},'%') OR category LIKE CONCAT('%',#{keyword},'%') OR software LIKE CONCAT('%',#{keyword},'%'))
    AND document_type = #{documentType}
    AND status = #{status}
    AND category = #{category}

ORDER BY updated_at DESC
